    """从多个候选中选择最好的"""
    best_score = -1
    best_idx = candidates[0]

    for i in candidates:
        remaining = s[:i] + s[i+1:]
        score = score_sp_sequence(remaining)
        if score > best_score:
            best_score = score
            best_idx = i

    return best_idx

def score_sp_sequence(s):
    """给双拼序列打分"""
    score = 0
    for i in range(0, len(s), 2):
        sm, ym = s[i], s[i+1]
        if sm in SHENGMU_KEYS:
            score += 1
        if ym in YUNMU_KEYS:
            score += 1
    return score

def main():
    with open('context/problems.json', 'r', encoding='utf-8') as f:
        problems = json.load(f)

    results = []
    failed = []

    for idx, s in enumerate(problems):
        result = find_extra_letter(s)
        results.append(result)
        if result == -1:
            failed.append((idx, s))

    with open('output.json', 'w', encoding='utf-8') as f:
        json.dump(results, f)

    print(f"Processed {len(results)} problems")
    print(f"Failed: {len(failed)}")

    if failed:
        print(f"\nFailed problems:")
        for idx, s in failed[:5]:
            print(f"  {idx}: len={len(s)}")

if __name__ == "__main__":
    main()"}

