VALID_FIRST_KEYS = SHENGMU_KEYS | YUNMU_KEYS  # 声母位置可以是声母键或韵母键（零声母）
VALID_SECOND_KEYS = YUNMU_KEYS  # 韵母位置必须是韵母键

