    n = len(s)
    candidates = []

    for i in range(n):
        remaining = s[:i] + s[i+1:]
        if try_parse_sp(remaining):
            candidates.append(i)

    if len(candidates) == 0:
        return -1
    elif len(candidates) == 1:
        return candidates[0]
    else:
        return select_best_candidate(s, candidates)

def select_best_candidate(s, candidates):
    """从多个候选中选择最好的"""
    # 策略：优先选择删除后能产生更多"标准"声母+韵母组合的位置
    best_score = -1
    best_idx = candidates[0]

    for i in candidates:
        remaining = s[:i] + s[i+1:]
        score = 0
        for j in range(0, len(remaining), 2):
