            # 标准声母得分更高
            if sm in SHENGMU_KEYS:
                score += 2
            else:
                score += 1  # 零声母
            if ym in YUNMU_KEYS:
                score += 1
        if score > best_score:
            best_score = score
            best_idx = i

    return best_idx

def main():
    with open('context/problems.json', 'r', encoding='utf-8') as f:
        problems = json.load(f)

    results = []
    failed = []

    for idx, s in enumerate(problems):
        result = find_extra_letter(s)
        results.append(result)
        if result == -1:
            failed.append((idx, s))

    with open('output.json', 'w', encoding='utf-8') as f:
        json.dump(results, f)

